function CanvasContainer({ canvasRef, objects, startDragging, dragging, stopDragging, setDoubleClickedObjId, doubleClickedObjId }) {
    function clientDoubleClicked (id) {
        setDoubleClickedObjId(id)
    }

    return (
        <div
            className="canvas-container"
            ref={canvasRef}
            onMouseMove={dragging}
            onMouseUp={stopDragging}
            style={{ position: 'relative' }}
        >
            {objects.map((obj) => (
                <div
                    key={obj.id}
                    className="obj"
                    onMouseDown={(e) => startDragging(obj.id, e)}
                    onMouseDown={() => clientDoubleClicked(obj.id)}
                    style={{
                        position: 'absolute',
                        left: obj.left,
                        top: obj.top,
                        backgroundColor: obj.color,
                        borderRadius: obj.radius,
                    }}
                />
            ))}
        </div>
    );
}

export default CanvasContainer;
